customCSS:
/* Theme Modal */
.modal { background: rgba(0,0,0,0.78) !important; backdrop-filter: blur(4px) !important; -webkit-backdrop-filter: blur(4px) !important; }
.modal-content { background: linear-gradient(180deg, rgba(22,22,22,0.98), rgba(5,5,5,0.98)) !important; border: 1px solid rgba(212,175,55,0.72) !important; border-radius: 8px !important; box-shadow: 0 18px 44px rgba(0,0,0,0.78), 0 0 24px rgba(50,205,50,0.16) !important; color: #fff !important; }
.modal-title, .settings-title, .modal-content h4 { color: #d4af37 !important; }
.app-dialog-message, .trigger-description, .community-template .description { color: #f2f2f2 !important; }
.import-hint, .settings-help, .hotkey-help, .range-labels, .community-template .task-count { color: #b8b8b8 !important; }
.community-template { background: rgba(0,0,0,0.46) !important; border: 1px solid rgba(212,175,55,0.24) !important; }
.modal-btn.primary { background: #4169e1 !important; border: 1px solid #6687ff !important; color: #fff !important; }
.modal-btn.secondary { background: #2b2b2b !important; border: 1px solid #666 !important; color: #fff !important; }
.modal-btn:hover { border-color: #d4af37 !important; box-shadow: 0 0 12px rgba(212,175,55,0.28) !important; }
.modal-content-dialog.app-dialog-tone-danger { border-color: #dc143c !important; }
.modal-content-dialog.app-dialog-tone-danger .modal-title { color: #ff6b86 !important; }
